import{_ as t,o as e,c as a,ag as o}from"./chunks/framework.WmBmIPw-.js";const m=JSON.parse('{"title":"贪心算法（构造式，Greedy for Construction）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristics/simple/greedy-algorithm.md","filePath":"or-opt/heuristics/simple/greedy-algorithm.md","lastUpdated":1777190173000}'),i={name:"or-opt/heuristics/simple/greedy-algorithm.md"};function l(s,r,n,h,c,d){return e(),a("div",null,[...r[0]||(r[0]=[o('<h1 id="贪心算法-构造式-greedy-for-construction" tabindex="-1">贪心算法（构造式，Greedy for Construction） <a class="header-anchor" href="#贪心算法-构造式-greedy-for-construction" aria-label="Permalink to &quot;贪心算法（构造式，Greedy for Construction）&quot;">​</a></h1><p>在组合优化构造阶段，贪心指：在尚未完成的解上，每一步在可行候选中，按立即可得的得分（边际长度、即时代价、按规则排序的优先序等）取当前看来最好的一步决策，不回溯、不把后步并入同一次全局优化里重解。是 <a href="./simple-heuristics.html">基础启发式</a> 中构造式的代表之一，与改进式邻域搜索相对。与动态规划、全局最短路等「在子结构上有最优性」的模型不同，贪心不保证在一般组合实例上全局最优。见 <a href="./../heuristic-algorithms.html">启发式算法总览</a> 中「一、基础启发式」下的构造式折叠。</p><hr><h2 id="模式与作用" tabindex="-1">模式与作用 <a class="header-anchor" href="#模式与作用" aria-label="Permalink to &quot;模式与作用&quot;">​</a></h2><ul><li><strong>典型流程</strong>：自空或根状态，重复「列出本步可行候选 → 用规则或键值选一个 → 定稿」直至完整可行解。</li><li><strong>常见用途</strong>：快出可行解和上界；作 <a href="./../meta/grasp.html">GRASP</a> 在 α=0 时 RCL 退化为纯贪心的起点；在分支定界或列生成中热启动或剪枝用界。</li><li><strong>不保证性</strong>：TSP 最近邻、背包按价值密度装等，都有反例使解任意劣于最优。工程上常先贪心，再 <a href="./k-opt.html">k-opt 系列</a> 或元启发式改进。</li></ul><hr><h2 id="例子-路径与列表调度" tabindex="-1">例子（路径与列表调度） <a class="header-anchor" href="#例子-路径与列表调度" aria-label="Permalink to &quot;例子（路径与列表调度）&quot;">​</a></h2><ul><li><strong>TSP 最近邻</strong>：自某起点，每步在未访点里选离当前最近者，直至全访完。复杂度常为 O(n²) 量级，解的质量与起点、并列时的处理约定有关。</li><li><strong>MST/集合覆盖等子问题</strong>：Prim、Kruskal 等有证明的贪心是该子问题的最优，但嵌在更大原模型里时，整体仍可能是启发式叙述。</li><li><strong>列表调度</strong>：如按截止期 EDD 排序后再顺排，是用贪心序驱动构造。</li></ul><hr><h2 id="与随机化、元启发式的衔接" tabindex="-1">与随机化、元启发式的衔接 <a class="header-anchor" href="#与随机化、元启发式的衔接" aria-label="Permalink to &quot;与随机化、元启发式的衔接&quot;">​</a></h2><ul><li><strong>RCL/GRASP</strong>：只取 c 最小可松成阈值内一批中随机，仍属构造侧；见 <a href="./../meta/grasp.html">GRASP</a> 的 RCL 与 α。</li><li><strong>与改进式链</strong>：常写「贪心得到 s → <a href="./hill-climbing.html">爬山</a> 或 <a href="./k-opt.html">k-opt 系列</a> 改进」的流水线。</li></ul><p><strong>注</strong>：教材里「贪心」有时能证最优；在运筹构造可行上界的笔记中，多数强调不证全局、只求快。读论文时以作者是否给出最优性或近似比为准。</p>',12)])])}const u=t(i,[["render",l]]);export{m as __pageData,u as default};
